commit 8b5e95b1fd2fa49a7c1607e294659f2c0ec12d69
Author: Hongyu Chen <xxs_chy@outlook.com>
Date:   Sun Feb 8 01:20:19 2026 +0800

    [InferAddressSpaces] Initialize op(generic const, generic const, ...) -> generic (#172143)

    Fixes #171890
    If the pointer operands of an instruction are all constants with generic
    AS, we always infer the AS of the instruction as uninitialized finally.
    And the rewrite process will skip cloning the instruction, producing
    invalid IR.
    This patch fixes it by inferring the AS of this kind of instruction as
    flat. Maybe we can fold the operator with all constants to get better
    performance, but I think this case is rare in the real world.

diff --git a/llvm/lib/Transforms/Scalar/InferAddressSpaces.cpp b/llvm/lib/Transforms/Scalar/InferAddressSpaces.cpp
index 03efc156df1e..93da510c5fbc 100644
--- a/llvm/lib/Transforms/Scalar/InferAddressSpaces.cpp
+++ b/llvm/lib/Transforms/Scalar/InferAddressSpaces.cpp
@@ -1102,7 +1102,8 @@ bool InferAddressSpacesImpl::updateAddressSpace(
   } else {
     // Otherwise, infer the address space from its pointer operands.
     SmallVector<Constant *, 2> ConstantPtrOps;
-    for (Value *PtrOperand : getPointerOperands(V, *DL, TTI)) {
+    SmallVector<Value *, 2> PtrOps = getPointerOperands(V, *DL, TTI);
+    for (Value *PtrOperand : PtrOps) {
       auto I = InferredAddrSpace.find(PtrOperand);
       unsigned OperandAS;
       if (I == InferredAddrSpace.end()) {
@@ -1133,12 +1134,18 @@ bool InferAddressSpacesImpl::updateAddressSpace(
       if (NewAS == FlatAddrSpace)
         break;
     }
+
     if (NewAS != FlatAddrSpace && NewAS != UninitializedAddressSpace) {
       if (any_of(ConstantPtrOps, [=](Constant *C) {
             return !isSafeToCastConstAddrSpace(C, NewAS);
           }))
         NewAS = FlatAddrSpace;
     }
+
+    // operator(flat const, flat const, ...) -> flat
+    if (NewAS == UninitializedAddressSpace &&
+        PtrOps.size() == ConstantPtrOps.size())
+      NewAS = FlatAddrSpace;
   }

   unsigned OldAS = InferredAddrSpace.lookup(&V);

tests.test_body:
target triple = "nvptx64--"

define ptr @pr171890(i1 %c) {
;
entry:
  %stack = alloca i16, align 2
  %const = getelementptr i8, ptr null, i64 1
  %sel = select i1 %c, ptr %stack, ptr %const
  ret ptr %sel
}
